var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"……돌아왔군. 집이야.","JPN":"……帰ってきたぜ。家だ。","ENG":"Finally... We're home.","TWN":"……回來了，到家了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"하아……. 무사귀환이라니 꿈만 같네요.","JPN":"はあ……無事帰還だなんて、夢みたいですね。","ENG":"*Sigh...* Can't believe we made it back.","TWN":"呼……竟然可以平安回來，好像真做夢一樣。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"그 괴물이 튀어나왔을 땐 정말 다 죽는 줄 알았다고요.","JPN":"あの化け物が飛び出してきた時には本当に全員死ぬかと思いました。","ENG":"I thought we were goners when that giant monster suddenly appeared.","TWN":"那個怪物冒出來的時候，我真的以為我們都會死掉。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"크큭. 이게 다 내가 준비해 간 폭탄 덕분인 줄 알아. 평생 감사하고 살아라, 이 자식아.","JPN":"ククッ、全部俺が用意した爆弾のおかげなんだぞ。一生感謝しろ、この野郎。","ENG":"Hahah. It's all thanks to my bombs, you hear? You ought to thank me for the rest of your life that you're still alive!","TWN":"咳咳，這都是拜我準備的炸彈所賜，記得要感謝我一輩子，你這臭小子。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"그 많은 폭약을 거기까지 실어 나른 건 저라고요.","JPN":"その大量の爆薬をあそこまで運んだのは僕ですよ。","ENG":"Hey, I'm the one who moved all that gunpowder, you know.","TWN":"把那麼多炸藥運到那裡的是我欸！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"그래도 뭐, 장교님께는 전부 와트 씨의 공이었다고 말씀드릴게요.","JPN":"でもまあ、将校には全部ワットさんの功績だったって言ってあげますよ。","ENG":"But, either way, I'll tell Officer Rashford that it was all you.","TWN":"反正我會跟軍官說，全都是華特先生的功勞啦！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"난 됐어. 그런 공로는 너나 받아라.","JPN":"俺はいい。功績はお前が持っていけ。","ENG":"Nah. You should take the credit.","TWN":"不需要，那些功勞送你吧。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"네? 왜요?","JPN":"えっ？　なんでですか？","ENG":"Huh? But why?","TWN":"嗯？為什麼？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"왜긴 왜야? 나 같은 중늙은이가 출세해서 뭐 하게?","JPN":"なんでって、俺みたいな中年が出世して何するんだよ。","ENG":"Why not? What's an old man like me supposed to do climbing up the ladder now?","TWN":"什麼爲什麼？我這個老頭子有什麼好爭的？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"아직 젊은 녀석이 평생 시골 수비대에서 썩을 생각이냐? 수도로 가서 큰일도 해 봐야지.","JPN":"まだ若いのに、一生田舎の守備隊で腐ってるつもりなのか？　首都で大きな仕事もやってみねえとな。","ENG":"But you. You're not thinking of staying here being a Border Guard forever, right? There are big things waiting for you in the capital.","TWN":"你還年輕，難道一輩子都打算待在鄉下的護衛隊嗎？你應該去首都闖闖。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"와트 씨…","JPN":"ワットさん……","ENG":"Mr. Watt...","TWN":"華特先生…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"다들 여기까지 오느라 수고 많았네.","JPN":"みんな、ここまでご苦労じゃったのう。","ENG":"You all did well coming back home safely.","TWN":"大家此行都辛苦了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"짐을 푸는 대로 식사나 하지.","JPN":"荷をほどき次第食事にしよう。","ENG":"Let's go eat after unpacking.","TWN":"放下行李就來吃飯吧。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"하하, 감자 냄새가 이렇게 반가울 줄이야.","JPN":"はは、ジャガイモの匂いがこんなに嬉しいなんてなぁ。","ENG":"Ha ha! Who would've thought the smell of potatoes could be so good!","TWN":"哈哈，沒想到聞到馬鈴薯的味道還會這麼開心。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"촌장, 내가 말한 건 준비해 뒀나?","JPN":"村長、私が言ったものは用意してくれたか？","ENG":"Chief, did you prepare what I asked for?","TWN":"村長，我說的東西你有準備嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"물론이지. 술이 아주 잘 익었더군. 대원들이 실컷 마시고도 남을 걸세.","JPN":"もちろんじゃ。酒がよく熟成しておった。隊員が存分に飲んでも余るじゃろう。","ENG":"Of course. The ale turned out splendid. There will be enough for everyone and more.","TWN":"當然，酒都準備好囉，隊員們儘管喝都還有剩呢。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"응? 술이라고요? 설마 그 감자 에일?","JPN":"うむ？　酒ですか？　まさか、あのジャガイモのエール？","ENG":"Hmm? Did you say, ale? Is that... spud ale?","TWN":"嗯？酒？是那個馬鈴薯啤酒嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그래. 정신머리 없는 것들이 귀한 식량을 빼돌려서 빚은 술이지.","JPN":"そう。頭がどうかしている人たちが貴重な食糧を横取りして作った酒ね。","ENG":"Yes. These two knuckleheads stole valuable food to brew it.","TWN":"沒錯，就是那些少根筋的傢伙，挪用珍貴糧食釀造的酒。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"특별한 날에 주려고 버리진 않았어. 오늘 같은 날 말이야.","JPN":"特別な日にあげようと思って捨てなかったんだ。今日のようにね。","ENG":"I didn't throw it away so I could give it to you all on a special occasion. A day like today, that is.","TWN":"我沒有扔掉，想說可以在特別的日子給大家喝，就像今天這樣。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"다들 대장 말 들었지? 오늘밤은 다들 원없이 마시도록.","JPN":"みんな、隊長の言葉を聞いたな？　今夜はみんなたくさん飲め。","ENG":"You heard our captain! Tonight, we drink to our heart's content!","TWN":"大家都有聽到隊長的話吧？今晚就喝個痛快。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"헤헤, 좋았어! 오늘 밤은 술잔치다!","JPN":"へへ、よっしゃ！　今夜は酒盛りだ！","ENG":"Heh heh! All right! It's gonna be a party tonight!","TWN":"嘿嘿，好欸！今晚要飲酒作樂！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"장교님도 함께하시죠! 오늘은 실컷 마시자고요!","JPN":"将校もご一緒にどうぞ！　今日はじゃんじゃん飲みましょうよ！","ENG":"Officer, join us! Let's drink until the sun comes up!","TWN":"軍官也一起來吧！今天喝個夠！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"피터! 장교님께 버릇없이 굴지 마라!","JPN":"ピーター！　将校に無礼だぞ！","ENG":"Peter! Show some respect!","TWN":"彼得！不得對軍官無禮！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"괜찮다. 귀관들이 불편하지 않다면 나도 참석하지.","JPN":"いい。貴官たちがいいのなら、私も参加しよう。","ENG":"It's all right. If it's okay with everyone, I'd like to join.","TWN":"不要緊，你們不介意的話，我也可以參加。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"엇, 정말 그래도 괜찮으시겠습니까?","JPN":"えっ、本当にそれでよろしいんですか？","ENG":"Oh, a-are you sure you're all right with that?","TWN":"呃，真的沒關係嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"야호! 어서 술을 나릅시다!","JPN":"ヤッホー！　早く酒を運びましょう！","ENG":"Woohoo! Let's get our drink on!","TWN":"呀呵！快倒酒！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"GUARD_BORDER_NULL_MULTI","text":{"KOREA":"성유물을 되찾아 온 장교님을 위하여! 건배!!","JPN":"聖遺物を取り戻した将校のために！　乾杯！！","ENG":"Cheers to Officer Rashford for bringing back the Holy Relic!!","TWN":"敬找回聖遺物的軍官一杯！乾杯！！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_CROWD_NOISE_04"},{"id":"L45_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"줄곧 느꼈지만, 여기 국경수비대는 군대가 아니라 좋은 친구 사이들 같네요.","JPN":"いつも思うんですけど、ここの国境守備隊は軍隊じゃなくて仲のいい友達のようですね。","ENG":"I get the feeling that the guards here are more like friends and family rather than an army.","TWN":"我一直覺得，這裡的國境護衛隊不像是軍隊，反而像是好朋友一樣。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"……네. 격식이 없다는 게 꼭 나쁘지만은 않네요.","JPN":"……はい。格式張らないというのは必ずしも悪いことではありませんね。","ENG":"Yes. But being casual isn't always a bad thing.","TWN":"……是，沒有規矩也不一定是壞事。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그간 저와 함께 다니느라 한나 씨도 고생하셨습니다. 같이 드시죠.","JPN":"ハンナさんも今まで私と行動を共にされてお疲れさまでした。一緒に飲みましょう。","ENG":"Thank you for coming with me all the way here, Miss Anderson. You should also have a drink.","TWN":"漢娜，你這段時間一直跟著我到處跑，辛苦了，一起喝一杯吧。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"아, 아뇨. 전 술은 못 마셔서요. 먼저 숙소로 들어가 볼게요.","JPN":"あ、いいえ。私、お酒は飲めないんですよ。先に宿に戻りますね。","ENG":"Oh, n-no thank you. I can't drink. But I'll meet you back at our room.","TWN":"哦，沒關係，我不會喝酒，我先回宿舍吧。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"그리고 누군가는 남아서 성유물을 지켜야 하니까요.","JPN":"あと、誰かは残って聖遺物を守らなきゃいけませんから。","ENG":"Also, someone has to keep an eye on the Holy Relic.","TWN":"而且必須有人要留下來保護聖遺物才行。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그런 이유라면 저도 가겠습니다.","JPN":"そういう理由でしたら私も行きます。","ENG":"If that's your reason why, then I shall go as well.","TWN":"那我也一起去吧。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"후후, 저는 정말 괜찮아요.","JPN":"ふふ、お気遣いなく。","ENG":"Hu hu. I'll be all right by myself.","TWN":"呵呵，我真的沒關係。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"오늘 열리는 잔치는 래시포드 씨가 주인공이잖아요. 어서 가 보세요.","JPN":"今日の宴会の主人公はラッシュフォードさんじゃないですか。早く行ってください。","ENG":"This party was meant for you, Miss Rashford. You should stay.","TWN":"你是今天這場宴會的主角，快過去吧。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"알겠습니다. 그럼 인사치레만 하고 빨리 돌아가기로 하죠.","JPN":"わかりました。それでは挨拶だけして、早く戻ります。","ENG":"Okay. Then I'll just exchange pleasantries and then quickly head back to you.","TWN":"好，那我去打聲招呼就回去。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"속여서 죄송해요, 래시포드 씨.","JPN":"騙してごめんなさい、ラッシュフォードさん。","ENG":"I'm sorry to deceive you, Miss Rashford.","TWN":"雷斯福特，很抱歉欺騙你。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"하지만 형제들의 사명을 이루려면……. 이럴 수밖에 없었어요.","JPN":"でも兄弟の使命を果たすためには……こうするしかなかったんです。","ENG":"But in order to fulfill my brothers' mission... I have no choice but to...","TWN":"但是要想完成兄弟們的使命… 就只能這麼做。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"여기에 있었군, 지휘관.","JPN":"ここにいたのか、指揮官。","ENG":"I've been looking for you, Commander.","TWN":"原來你在這裡，指揮官。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_DOOR_WOOD"},{"id":"L18_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"장교님?","JPN":"将校？","ENG":"Officer Rashford...?","TWN":"軍官？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"다른 병사들은 먹고 마시기 바쁜데, 여기서 혼자 뭐 하고 있는 거지?","JPN":"他の兵士はひたすら飲み食いしているというのに、ここで一人何をしてるんだ？","ENG":"Everyone's busy drinking and laughing, but what are you doing alone in here?","TWN":"別的士兵都忙著吃東西，你一個人在這裡做什麼？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이번 전투 중에 총이 망가져서 손을 좀 보고 있었습니다.","JPN":"今度の戦闘で銃が壊れましたので、手入れをしていました。","ENG":"My rifle broke during battle, so I was giving it some elbow grease.","TWN":"我的槍在這次作戰時有些毀損，我正在修呢。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"재미없는 녀석이군. 오늘은 나라의 숙원을 이룬 날로 기록될 텐데.","JPN":"つまらないやつだな。今日は国の宿願を叶えた日として記録に残るだろうに。","ENG":"You're no fun, are you? Today will be recorded as the day where we accomplished one of this country's long-awaited goals.","TWN":"你真沒意思，今天是國家的大日子，"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"받아라. 내가 주는 술을 못 마신다고 하진 않겠지?","JPN":"受け取れ。私がついだ酒を飲めないとは言わないだろうな？","ENG":"Here. You won't say no to a drink I'm giving you, right?","TWN":"拿著，你應該不會拒絕我給你的酒吧？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"신경 써 주셔서 감사합니다.","JPN":"お気遣いありがとうございます。","ENG":"Thank you.","TWN":"謝謝你的酒。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"흐음… 20년 전 총사대에서 쓰던 총기 모델인가?","JPN":"ふむ……20年前に銃士隊で使っていた銃器のモデルか？","ENG":"Hmm... Isn't that the model that was used 20 years ago by the Musketeer Division?","TWN":"嗯……這是 20年前在射擊隊使用的槍支模組嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이왕이면 신품으로 바꾸도록. 내가 지원해 주겠다.","JPN":"どうせなら新品に交換しろ。私が支援してやる。","ENG":"Why not just get a new one? I can help you with that.","TWN":"既然如此，乾脆換新的吧，我支援你。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"말씀은 감사합니다.","JPN":"ありがたいお言葉です。","ENG":"Thank you, but I must decline.","TWN":"謝謝你的好意。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"하지만 이건 허밋과 함께 제 과거를 대신 기억해 주는 몇 안 되는 물건입니다.","JPN":"ですが、これはハーミットと共に私の過去を記憶してくれている数少ない物です。","ENG":"This rifle is one of the few things that reminds me of my past, along with Hermit.","TWN":"但這個和赫米特是少數有我過去記憶的東西。 "},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"적어도 기억을 완전히 되찾기 전까지는 함부로 버릴 생각이 없습니다.","JPN":"少なくとも記憶を完全に取り戻すまでは、むやみに捨てるつもりはありません。","ENG":"I don't plan on throwing it away until I've at least recovered all of my memories.","TWN":"至少在完全恢復記憶之前，我不打算隨便扔掉。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"참 남다른 고집불통이군.","JPN":"まったく、本当に頑固だな。","ENG":"My, aren't you a stubborn one.","TWN":"真是有夠固執的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"좋았어. 잠깐 비켜 봐라. 내가 직접 봐 주지.","JPN":"よし。ちょっとどいてみろ。私が直接見てやろう。","ENG":"All right. Move over. Let me take a crack at it.","TWN":"好吧，你讓讓，我親自看看。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"취하신 것 같은데, 괜찮겠습니까?","JPN":"酔っているみたいですが、大丈夫ですか？","ENG":"You seem drunk. Are you okay?","TWN":"你好像有點醉，沒問題嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"흥, 차기 수석 기술자를 우습게 보지 마라!","JPN":"フン、次期首席技術者をなめるな！","ENG":"Hmph! Don't you underestimate a Royal Chief Technician candidate!","TWN":"哼，別小看下任首席技師軍官！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"팔도 다친 주제에 끙끙대지 말고 비켜!","JPN":"腕を怪我しているくせに、唸ってないでどけ！","ENG":"Stop fiddling around with your broken arm, and move aside!","TWN":"你自己還不是手臂受傷，別吵，讓開！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"으음… 뭐지? 내가 배운 구형 모델의 설계와 다르잖아?","JPN":"うーむ……何だ？　私が教わった旧型モデルの設計とは違うな。","ENG":"Hmm... Huh? Why's this designed differently from the old models I've seen?","TWN":"呃…這是什麼？怎麼和我學過的舊款模組不一樣？"},"stage":{"bg":"BLACK","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"아니, 총기로서의 기본동작원리는 거의 같지만… 프레임에 미세한 차이가 있어.","JPN":"いや、銃器としての基本作動原理はほとんど同じなんだが……フレームが微妙に違う。","ENG":"Wait... The basic mechanisms are almost the same, but... There's tiny differences in the frame.","TWN":"不，槍支的基本原理幾乎都相同…只是框架有些微的差異。"},"stage":{"bg":"BLACK","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"마치 있어야 할 부분이 사라진 것 같은…","JPN":"まるで、あるはずの部分が消えてなくなったような……","ENG":"It's as if something that should be here is missing...","TWN":"好像有些部分不見了…"},"stage":{"bg":"BLACK","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"괜찮으십니까? 점점 얼굴이 붉어지고 있습니다만.","JPN":"大丈夫ですか？　段々顔が赤くなっていますが。","ENG":"Are you sure you're okay? Your face is getting redder and redder.","TWN":"你沒事吧？你的臉似乎越來越紅。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"지, 집중에 방해된다. 말 걸지 마.","JPN":"しゅ、集中の邪魔だ。話しかけるな。","ENG":"I-I'm trying to focus! Don't talk to me.","TWN":"我…我在專心，別吵我。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L47_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"혹시 전투 중에 총기가 파손되거나 부품을 잃어 버린 적 없나?","JPN":"もしかして戦闘中に銃器が壊れたとか、部品がなくなったことはなかったか？","ENG":"Hey, did your weapon get damaged during battle or did you lose any parts?","TWN":"有沒有在戰鬥中槍支受損，或是弄丟零件過？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"제가 기억하는 원형 그대로입니다. 그랬으면 눈치를 챘겠죠.","JPN":"私が記憶してる原型そのままです。もしそうなら気付いたはずです。","ENG":"The rifle is exactly the same as I remember it. If I'd lost something I would've noticed it.","TWN":"這和我印象中的樣子是一樣的，若是有應該會發現吧？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"흐응……. 그렇단 말이지.","JPN":"ふーん……なるほどな。","ENG":"Hmm... If you say so.","TWN":"嗯嗯……説得也對。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"일단 구부러진 노리쇠와 망가진 실린더는 고쳐 뒀다. 당장 쓰기엔 지장 없을 거야.","JPN":"いったん曲がった遊底と壊れたシリンダーは直しておいた。すぐ使えるだろう。","ENG":"I fixed the bent bolt and the damaged cylinder. You’ll be able to use it without a problem now.","TWN":"我先幫你把彎掉的扣環和壞掉的槍筒修好了，用起來應該沒什麼問題。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"감사합니다.","JPN":"ありがとうございます。","ENG":"Thank you.","TWN":"謝謝。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"아. 그러고 보니 이걸 돌려드리는 걸 깜빡했군요.","JPN":"あ。そういえばこれを返すのを忘れていました。","ENG":"Oh, that's right I forgot to return this to you.","TWN":"話說回來，差點忘記這個要還你。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이건…… 내 펜던트? 언제부터 가지고 있던 거지?","JPN":"これは……私のペンダント？　いつから持っていたんだ？","ENG":"Is that... my pendant? How long have you had it?","TWN":"這是…… 我的掛飾？怎麼會在你那裡？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그 분류 미상의 침식체에게 공격 받았을 때 떨어트리셨더군요.","JPN":"あの分類未詳の侵食体に攻撃された時、落とされました。","ENG":"You dropped it when that unclassified C.O. ambushed you.","TWN":"是你被那個類別不明的侵蝕體攻擊時掉下來的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"가지고 있는 동안 증폭기를 삽입해서 부족한 출력 문제를 개선해 봤습니다.","JPN":"持っている間、増幅器を入れて出力が足りない問題を改善してみました。","ENG":"While I had it with me, I inserted an amplifier to fix the output issue it had.","TWN":"我有插入增幅器，改善輸出不足的問題。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"한 번밖에 쓸 수 없으니 시험해 보진 못했지만, 아마 반경 100미터까지는 간섭이 가능할 겁니다.","JPN":"一度しか使えないのでテストはできませんでしたが、多分半径100メートルまでは干渉できるはずです。","ENG":"I wasn't able to test it out since there's only one charge left, but I believe it'll be able to cover a radius of about 100m or so.","TWN":"因爲只能用一次，所以沒試過，但半徑100公尺內應該都沒問題。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"100미터…… 라고?","JPN":"100メートル……だと？","ENG":"100m...?!","TWN":"100公尺……？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"잠깐! 누가 멋대로 내 물건을 개조해도 좋다고 했나?!","JPN":"待て！　誰が勝手に改造していいと言った！？","ENG":"Wait! Who told you that you could tamper with my stuff?!","TWN":"等等！誰說你可以隨便改造我的東西？！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"제 판단이 장교님의 심기를 거슬렀다면 죄송합니다.","JPN":"私の判断が将校のご機嫌を損なったのなら、申し訳ありません。","ENG":"I apologize if my actions have offended you.","TWN":"如有冒犯，我很抱歉。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"아니야. 언성을 높여 미안하군.","JPN":"いや。大声を出してすまない。","ENG":"N-never mind. I'm sorry for yelling at you.","TWN":"沒事，抱歉，我嗓門太大。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"나는 귀관에게 사과 받을 입장이 못 돼. 거짓말을 했으니까.","JPN":"私は貴官に謝られる立場ではない。嘘をついたんだからな。","ENG":"I'm not in a position where I can accept your apology since I lied to you.","TWN":"我沒理由接受你的道歉，因爲我說謊。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"거짓말이라고 하셨습니까?","JPN":"嘘とおっしゃいましたか？","ENG":"Did you say you lied to me?","TWN":"你說謊？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이건 장교들에게 지급되는 물건 같은 게 아니야. 어머니가 남겨 주신 소중한 유품이지.","JPN":"これは将校に支給されるものなどではない。母が残した大事な遺品だ。","ENG":"This isn't issued to officers of the army. It's actually a memento handed down to me by my mother.","TWN":"這不是配給軍官的東西，是我母親留下的珍貴遺物。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이런. 원형 그대로를 간직해야 할 물건에 제가 몹쓸 짓을 하고 말았군요.","JPN":"なんと。元のままにしておかなければならないものに私が余計なことをしてしまいましたね。","ENG":"Oh dear. It seems that I made a mistake to improve it when it should've been left in its original state.","TWN":"糟糕，那應該要好好保留原貌的，我竟然做出這麼糟糕的事。 "},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"꼬투리 잡는 거 아니야!","JPN":"責めてるわけではないんだ！","ENG":"I'm not saying that it's your fault!","TWN":"我沒有怪你的意思！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L19_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그만큼 중요한 거라서… 고맙다는 말을 하고 싶을 뿐이니까.","JPN":"そのくらい大事なものだから……感謝の言葉を伝えたかっただけだ。","ENG":"But it's important to me... So I wanted to thank you.","TWN":"這對我很重要…我只是想說聲謝謝而已。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"분실물을 찾아다 드렸을 뿐입니다. 별말씀을.","JPN":"落とし物を見つけてお渡ししただけです。どういたしまして。","ENG":"No need. I only returned what’s yours to begin with.","TWN":"我只是幫你找回遺失的東西，不用這麼客氣。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"능청스러운 놈…….","JPN":"ずうずうしいやつ……","ENG":"You and your sly tongue...","TWN":"真會說好聽話……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그래서, 한 가지 묻고 싶다.","JPN":"それで、一つ聞きたいんだが。","ENG":"Anyway, I have a question for you.","TWN":"我想問你一件事，"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"혹시 그 시신들을 보고…… 총사대원들의 최후가 어땠는지 떠올랐나?","JPN":"もしかしてあの死体を見て……銃士隊員の最期がどうだったか思い出したか？","ENG":"When you saw those corpses... Could you remember anything of how they might've ended up like that?","TWN":"你看到那些屍體……有想起射擊隊員那時候的情形嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"……아니요. 무엇 하나 떠올리지 못했습니다.","JPN":"……いいえ。何一つ思い出せませんでした。","ENG":"Unfortunately, no. I couldn't remember anything back there.","TWN":"……沒有，我什麼都沒想起來。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"성유물을 노린 자의 짓이라고 막연하게 생각했지만, 어쩌면 다른 이유일지도 모릅니다.","JPN":"聖遺物を狙っていた者の仕業だと漠然と思っていたのですが、もしかすると別の理由だったのかもしれません。","ENG":"I assume whoever was after the Holy Relic did that, but perhaps there could be another reason.","TWN":"雖然覺得這是覬覦聖遺物的人所爲，但也許有其他原因。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"다른 이유?","JPN":"別の理由？","ENG":"Another reason?","TWN":"其他原因？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"제 기억 중에 아직 말씀드리지 못한 사실이 하나 있습니다.","JPN":"記憶している中で､ひとつだけまだ申し上げていない事実があります｡","ENG":"There are some memories that I haven't told you about yet.","TWN":"在我的記憶中，還有一件事沒有告訴你。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"왜 감추고 있었지? 내가 알아선 안 될 내용이라도 되는 건가?","JPN":"どうして隠していたんだ？　私が知ってはいけない内容なのか？","ENG":"Why haven’t you told me? Is it something I shouldn't know about?","TWN":"爲何不說？難道是怕我知道嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"장교님의 신뢰를 잃을 거라고 생각했기 때문입니다.","JPN":"将校の信頼を失うことになると思ったからです。","ENG":"I didn’t tell you because I thought it might make me lose your trust.","TWN":"因爲我以為會失去軍官的信任。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그래? 그렇다면 왜 이제 와서 말하는 거지? 네놈도 내가 지긋지긋해진 건가?","JPN":"そうなのか？　それならなぜ今更話すんだ。貴様も私にうんざりしてきたのか？","ENG":"Hmm? Then why are you telling me now? Do you want me to not trust you anymore?","TWN":"是嗎？那爲什麼現在要說？ 你不怕嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"장교님이라면 제 1 총사대의 명예를 회복시켜 주실 거라고 믿기 때문입니다.","JPN":"将校なら第1銃士隊の名誉を取り戻してくださると信じているからです。","ENG":"I'm telling you because I trust that you'll restore the honor of the 1st Musketeer Division.","TWN":"因爲我相信，若是你，一定能夠恢復第1射擊隊的名聲。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그럴싸한 이유군. 말해 봐라.","JPN":"もっともらしい理由だな。話してみろ。","ENG":"I see. Keep going.","TWN":"真是個好理由，你說看看。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"제가 기억하는 과거의 단편에서, 저는 제 손으로 부관을 찔렀습니다.","JPN":"記憶している過去の断片の中で、私は自らの手で副官を刺しました。","ENG":"In one of my fragmented memories, I stabbed my own adjutant.","TWN":"在我過去的記憶中，是我親手刺傷副隊長的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"자신의 부하를……? 그가 성유물을 탐내서 배반이라도 했나?","JPN":"自分の部下を……？　その者が聖遺物欲しさに裏切ったのか？","ENG":"Your own men...? Did you think he was after the Holy Relic?","TWN":"刺傷自己的部下…？他有覬覦聖遺物嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"모르겠습니다. 어쩌면 반대로 성유물의 정체를 알던 제가 부하를 배반한 것일지도 모르죠.","JPN":"わかりません。もしかしたら逆に聖遺物の正体を知っていた私が、部下を裏切ったのかもしれません。","ENG":"I don't know. Or it could have been me who betrayed my men.","TWN":"我不知道，或許是反過來，是我知道聖遺物後背叛部下也不一定。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"배반……. 배반이라고 했겠다.","JPN":"裏切り……裏切りと言ったか？","ENG":"\\"Betray\\", you say...","TWN":"背叛…… 你是說背叛。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이 자리에서 확실히 말해 두지. 귀관은 전우에게 악의를 품을 인물로 보이지 않는다.","JPN":"この場ではっきり言っておこう。貴官は戦友に悪意を抱くような人物には見えない。","ENG":"Let me make something clear. I do not see you as someone who hold ill will towards your men.","TWN":"你說清楚，你看起來不像是會對戰友心懷不軌的人。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"처음 들어 보는 호평이군요.","JPN":"初めて聞く好評ですね。","ENG":"That's the first compliment I've heard from you.","TWN":"第一次有人誇獎我呢聽。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"추후 사건에 대한 조사가 본격적으로 진행되면 그 진상도 규명될 수 있을 거다.","JPN":"今後、事件について本格的に調査が始まればその真相も明らかになるだろう。","ENG":"What actually happened is bound to be revealed when the investigation properly starts.","TWN":"以後若針對事件展開正式調查，真相也會查明的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그 자리에 있었던 부대원들의 희생은 단 하나도 헛되게 하지 않겠어.","JPN":"その場にいた部隊員の犠牲は、何一つ無駄にはしない。","ENG":"I'll make sure none of those who fell that day will die in vain.","TWN":"我不會讓那些隊員白白犧牲的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"감사합니다. 그렇게 말씀해 주시니 한결 마음이 놓이는군요.","JPN":"ありがとうございます。そう言ってくださると一安心ですね。","ENG":"Thank you. Hearing you say that actually takes some weight off my shoulders.","TWN":"謝謝！聽你我放心許多。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그래서 말인데…….","JPN":"それでだが……","ENG":"So I was thinking...","TWN":"所以……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"귀관도 내일 우리와 함께 수도로 가지 않겠나?","JPN":"貴官も明日我々と共に首都に行かないか？","ENG":"Will you go to the capital with me tomorrow?","TWN":"你明天可以和我們一起去首都嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"수도로 말입니까?","JPN":"首都にですか？","ENG":"The capital?","TWN":"首都嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그곳에서 귀관의 침식 증후군 치료를 도와 주지. 신변은 내가 보장해 주겠다.","JPN":"そこで貴官の侵食症候群の治療に助力しよう。身の回りのことは私が保障してやる。","ENG":"There, we can find a way to treat your Corruption Syndrome. And I'll vouch for your safety.","TWN":"我會在那裡幫你治療侵蝕症候群，我會保障你的人身安全。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"제가 침식증후군이 있다는 걸 알고 계셨습니까?","JPN":"私が侵食症候群であることを知っていたのですか？","ENG":"How long have you known that I have Corruption Syndrome?","TWN":"你知道我有侵蝕症候群嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"귀관을 병실로 데려갔던 날… 잠결에 들었다.","JPN":"貴官を病室に連れていった日……夢うつつで聞いた。","ENG":"On the day I carried you to the hospital room… I heard about it while asleep.","TWN":"是我把你送到病房那天…半夢半醒時聽到的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"아무튼 왕실에는 귀관 같은 말기 환자들을 여러 명 담당해 본 명의도 있어.","JPN":"とにかく、王室には貴官のような末期患者を何人も担当した名医もいるんだ。","ENG":"Anyway, there are many doctors who are capable of treating end-stage patients like yourself.","TWN":"總之在皇室有一位名醫，他曾經負責過治療幾位像你一樣的末期病患。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"여기서 지내는 것보단 훨씬 덜 힘들 거야.","JPN":"ここで過ごすよりはもっと楽だろう。","ENG":"So it'll be a lot easier for you if you stay there compared to here.","TWN":"生活會比這裡舒適許多。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"제안해 주셔서 감사하지만, 받아들이기는 어렵겠습니다.","JPN":"ご提案はありがたいのですが、お受けすることはできません。","ENG":"Thank you for the offer, but I’m afraid I can’t accept.","TWN":"謝謝你的提議，但我不能接受。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"몇 번 신세를 지고 나니 병상보다는 벌판의 그루터기가 더 편하더군요.","JPN":"何度かお世話になってみると、病床よりは野原の切り株の方が気楽でしたので。","ENG":"After being in and out of the hospital, I feel more at ease out in the field than in a hospital bed.","TWN":"經過這幾次，我發現比起病床，原野上的樹樁更舒服。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…그렇군. 귀관의 뜻이 정 그렇다면 더는 강요하지 않겠다.","JPN":"……そうか。貴官の意思がそうならもう強要はしない。","ENG":"...I see. If that is your decision, then I won't force you.","TWN":"…原來如此，既然你的意思如此，那我便不再強求。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"저희 부대가 도움이 되었기를.","JPN":"我々の部隊はお役に立てたでしょうか。","ENG":"I hope that my men were of help to you.","TWN":"希望我們的部隊有幫上忙。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"물론이다. 인재를 둘이나 놓치게 만들다니 괘씸한 부대이긴 하지만.","JPN":"もちろんだ。人材を二人も留めておく、けしからん部隊ではあるがな。","ENG":"Of course. I'm just annoyed to that I have to let go of two talented individuals here.","TWN":"當然，雖然我痛失二個人才，這一點有點可惡。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그럼, 이 마지막 한 잔으로 작별이군.","JPN":"それじゃ、この最後の一杯でお別れだ。","ENG":"Then, I guess this will be our farewell.","TWN":"那我喝完最後一杯就先行告辭。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"앞서 쓰러져간 이들의 이름이, 당신의 의지와 함께하길.","JPN":"先に倒れていった者たちの名が、あなたの意志と共にあらんことを。","ENG":"May the names of those who have fallen before you be with your determination.","TWN":"願先前倒下之人之名，與你的意志同在。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"당신의 이름이, 앞서 쓰러져간 이들의 의지와 함께하길.","JPN":"あなたの名が、倒れていった者たちの意志と共にあらんことを。","ENG":"May your name be with the determination of those who have fallen before you.","TWN":"願你的名字，與先前倒下之人之意志同在。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};